sql:
SELECT state
FROM postcodes
WHERE median_age > 45;

SELECT AVG(median_income) 
FROM postcodes
WHERE state = 'Northern Territory' AND median_age >= 30;

SELECT ROUND(median_age, 2) AS median_age
FROM postcodes
WHERE postcode = 810;

SELECT MAX(p.population)
FROM postcodes p
WHERE SUBSTR(p.postcode, 1, 1) = '8';

SELECT access_time, data_accessed
FROM access_logs
WHERE user_id IN (0, 1);

SELECT d.average_rent, d.employment_rate, l.access_time
FROM demographic_data d, access_logs l
WHERE d.year = 2022 AND l.access_time LIKE '%2022%';

SELECT year, MAX(average_rent) AS max_average_rent
FROM demographic_data
GROUP BY year;

SELECT postcode, median_income
FROM postcodes
WHERE median_income > (SELECT AVG(median_income) FROM postcodes);

SELECT SUM(population) AS total_people
FROM postcodes
WHERE state = 'Northern Territory';

external_knowledge:
- The term "predominantly high school educated residents" refers to areas where the average education level is 'High School'. ;
- The average rent comparison is used to identify more expensive or less affordable areas compared to the baseline of high school educated residents. ;
- Ordering by postcode ensures the list is organized alphabetically or numerically based on the postcodes.

sql:
SELECT postcode_id, state, median_income
FROM postcodes
ORDER BY median_income DESC;
